args.sparql:
SELECT ?chiefGuest ?chiefGuestLabel WHERE {
  ?event wdt:P17 wd:Q28;
         wdt:P585 ?date.
  FILTER(?date >= "2017-08-15"^^xsd:date && ?date < "2017-08-16"^^xsd:date).
  ?event wdt:P1265 ?chiefGuest.
  ?chiefGuest rdfs:label ?chiefGuestLabel.
  FILTER(LANG(?chiefGuestLabel) = "en").
}

SELECT ?event ?eventLabel WHERE {
  ?event wdt:P17 wd:Q28;
         wdt:P585 ?date.
  FILTER(?date = "2017-08-15T00:00:00Z"^^xsd:dateTime).
  ?event rdfs:label ?eventLabel.
  FILTER(LANG(?eventLabel) = "en").
}

